export interface Customer {
  yearsWithMHPCO: number;
}

export interface Item {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
}

export interface QuoteStep {
  op: 'quote';
  items: Item[];
}

export interface Damage {
  itemType: string;
  amount: number;
}

export interface Incident {
  cause: string;
  damages: Damage[];
}

export interface ClaimStep {
  op: 'claim';
  policy: number;
  incident: Incident;
}

export type Step = QuoteStep | ClaimStep;

export interface Scenario {
  customer: Customer;
  steps: Step[];
}

export interface QuoteResult {
  premium: number;
}
export interface ClaimResult {
  payout: number;
  remainingCap: number;
}
export type StepResult = QuoteResult | ClaimResult;

export interface ScenarioResult {
  results: StepResult[];
}

const MAIN_ITEM_PRICES: Record<string, { value: number; premium: number }> = {
  sword: { value: 1000, premium: 100 },
  amulet: { value: 600, premium: 60 },
  staff: { value: 800, premium: 80 },
  potion: { value: 400, premium: 40 },
};

const COMPONENT_TYPES = new Set(['rune', 'moonstone']);

function itemBasePremium(item: Item): number {
  const main = MAIN_ITEM_PRICES[item.type];
  if (main) return main.premium;
  if (COMPONENT_TYPES.has(item.type)) return 25;
  throw new Error(`Unknown item type: ${item.type}`);
}

function itemSurcharge(item: Item): number {
  const base = itemBasePremium(item);
  let surcharge = 0;
  if (item.cursed) surcharge += base * 0.5;
  if ((item.enchantment ?? 0) >= 5) surcharge += base * 0.3;
  return surcharge;
}

function quoteStepPremium(items: Item[], customer: Customer): number {
  let policyBase = 0;
  let itemSurcharges = 0;
  for (const it of items) {
    policyBase += itemBasePremium(it);
    itemSurcharges += itemSurcharge(it);
  }
  let policyMods = 0;
  if (customer.yearsWithMHPCO >= 2) policyMods -= policyBase * 0.2;
  policyMods += policyBase * 0.1; // first insurance surcharge
  const total = policyBase + itemSurcharges + policyMods + 5;
  return Math.ceil(total);
}

export function runScenario(scenario: Scenario): ScenarioResult {
  const results: StepResult[] = [];
  for (const step of scenario.steps) {
    if (step.op === 'quote') {
      results.push({ premium: quoteStepPremium(step.items, scenario.customer) });
    } else {
      results.push({ payout: 0, remainingCap: 0 });
    }
  }
  return { results };
}

